--
-- Table structure for table `hechos_resumen_regional_anual`
--

DROP TABLE IF EXISTS `hechos_resumen_regional_anual`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `hechos_resumen_regional_anual` (
  `tiempo_id` int DEFAULT NULL,
  `region_id` int DEFAULT NULL,
  `monto_total_invertido` bigint DEFAULT NULL,
  `cantidad_proyectos` int DEFAULT NULL,
  `monto_promedio_proyecto` decimal(15,2) DEFAULT NULL,
  KEY `tiempo_id` (`tiempo_id`),
  KEY `region_id` (`region_id`),
  CONSTRAINT `hechos_resumen_regional_anual_ibfk_1` FOREIGN KEY (`tiempo_id`) REFERENCES `dim_tiempo` (`tiempo_id`),
